class Solution:
    def calc(self, s: str) -> int:
        values = []  # Stack for numbers
        ops = []      # Stack for operators
        i = 0
        n = len(s)

        while i < n:
            char = s[i]

            if char.isspace():
                i += 1
                continue

            if char.isdigit():
                num = ""
                # Parse the full number
                while i < n and s[i].isdigit():
                    num += s[i]
                    i += 1
                values.append(int(num))
                # After reading the number, we need to potentially process pending operations
                while ops and values:
                    op = ops.pop()
                    val2 = values.pop()
                    val1 = values.pop()
                    if op == '+':
                        values.append(val1 + val2)
                    elif op == '-':
                        values.append(val1 - val2)
                    # Since only + and - are allowed, no division/multiplication handling needed here.

            elif char == '(':
                ops.append(char)

            elif char == ')':
                # Evaluate everything inside the parentheses
                while ops[-1] != '(':
                    if not values:  # Should not happen in valid input
                        raise ValueError("Invalid expression: Mismatched parentheses")
                    op = ops.pop()
                    val2 = values.pop()
                    val1 = values.pop()
                    if op == '+':
                        values.append(val1 + val2)
                    elif op == '-':
                        values.append(val1 - val2)

                # Pop the opening '('
                ops.pop()

            elif char in ('+', '-'):
                # Standard left-to-right evaluation for equal precedence operators (+, -)
                while ops and ops[-1] != '(':
                    op = ops.pop()
                    val2 = values.pop()
                    val1 = values.pop()
                    if op == '+':
                        values.append(val1 + val2)
                    elif op == '-':
                        values.append(val1 - val2)

                ops.append(char)

            i += 1

        # Process any remaining operations
        while ops:
            op = ops.pop()
            if not values:
                 raise ValueError("Invalid expression: Missing operands")

            val2 = values.pop()
            val1 = values.pop()

            if op == '+':
                values.append(val1 + val2)
            elif op == '-':
                values.append(val1 - val2)

        # The final result should be the single remaining element in values
        return values[0] if values else 0

