        (100, 'C'), (90, 'XC'), (50, 'L'), (40, 'XL'),
        (10, 'X'), (9, 'IX'), (5, 'V'), (4, 'IV'),
        (1, 'I')
    ]

    result = []
    remaining_n = n

    for value, symbol in mapping:
        if remaining_n == 0:
            break

        # Determine how many times this symbol value fits into the remaining number
        count = remaining_n // value

        if count > 0:
            result.append(symbol * count)
            remaining_n -= value

    return "".join(result)

